+fn contains_identifier(text: &str, expected_marker: &str) -> bool {
+    text.split(|ch: char| !(ch.is_ascii_alphanumeric() || ch == '_'))
+        .collect::<Vec<_>>()
+        .contains(&expected_marker)
+}
